import{_ as s,o as t,c as n,a3 as i}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"84. Translation Arrangements For Registered Nurses Midwives","description":"","frontmatter":{"title":"84. Translation Arrangements For Registered Nurses Midwives","eba":"Nurses and Midwives 2024-2028","topics":["preliminary"]},"headers":[],"relativePath":"ebas/nurses-midwives/classification-staffing/84-translation-arrangements-for-registered-nurses-midwives.md","filePath":"ebas/nurses-midwives/classification-staffing/84-translation-arrangements-for-registered-nurses-midwives.md"}'),a={name:"ebas/nurses-midwives/classification-staffing/84-translation-arrangements-for-registered-nurses-midwives.md"};function r(o,e,l,d,g,c){return t(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="_84-translation-arrangements-for-registered-nurses-midwives" tabindex="-1">84. Translation Arrangements For Registered Nurses Midwives <a class="header-anchor" href="#_84-translation-arrangements-for-registered-nurses-midwives" aria-label="Permalink to &quot;84. Translation Arrangements For Registered Nurses Midwives&quot;">​</a></h1><p><strong>84.1</strong> Translation to four stream grading structure</p><p><strong>(a)</strong> The translation arrangements in <a href="/eba/ebas/nurses-midwives/classification-staffing/85-ruson-rusom-classifications.html">clause 85</a> of the 2016 Agreement continue to apply unless a specific clause of this Agreement is inconsistent, in which case the provisions of this Agreement apply to the extent of the inconsistency.</p><p><strong>(b)</strong> Previous experience at a Level or increment will count as experience for the purposes of translation and all other purposes under this Agreement and the 2016 Agreement.</p><p><strong>84.2</strong> Research Nurse/Midwife Translation Arrangements</p><p>The translation arrangements in <a href="/eba/ebas/nurses-midwives/classification-staffing/82-enrolled-nurses-classification.html">clause 82.3</a> of the 2016 Agreement continue to apply to Research Nurses/Midwives employed as at 31 March 2012.</p><p><strong>84.3</strong> Nurse/Midwife Manager 5 and above Translation Arrangements</p><p>The translation arrangements in the 2020 Agreement continue to apply to Nurse/Midwife Manager 5 and above.</p><p><strong>84.4</strong> Nurse/Midwifery Unit Manager Classification</p><p><strong>(a)</strong> Nurse Unit Managers and Midwife Unit Managers will be graded at either NM2, NM3 or NM4 in accordance with this clause.</p><p><strong>(i)</strong> A NUM/MUM whose position was graded in accordance with the 2016 Agreement, or 2020 Agreement will continue at the grade determined under that agreement process, subject to (iii) below.</p><p><strong>(ii)</strong> A NUM/MUM position to which (i) does not apply will be graded according to (iii) and (iv) below.</p><p><strong>(iii)</strong> Where a new NUM/MUM position is created, or there is a substantial change to an existing NUM/MUM position, the position will be matched against the Matrix at <a href="/eba/ebas/nurses-midwives/appendices/07-num-mum-matrix.html">Appendix 7</a>.</p><p><strong>(iv)</strong> The VHIA and the ANMF will collaboratively assess the responses to the Matrix to determine the relevant grade.</p><p><strong>(v)</strong> No decision at (iv) above can result in a grade at NM2 for a position held by a NUM/MUM since 1 July 2022.</p><p><strong>(vi)</strong> Disputes regarding the application of (iii) and (iv) above will be determined in accordance with <a href="/eba/ebas/nurses-midwives/consultation-disputes/14-statewide-industry-panel.html">clause 14</a>.</p><p>Plain language terms: RN translation, midwife translation, transition to new classification.</p>',17)])])}const u=s(a,[["render",r]]);export{m as __pageData,u as default};
